class Solution {
    public boolean makeStringsEqual(String s, String target) {
        int cntS = 0, cntT = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '1') cntS++;
            if (target.charAt(i) == '1') cntT++;
        }
        return cntS == 0 && cntT == 0 || cntS > 0 && cntT > 0;
    }
}
